import { Injectable, Type } from '@angular/core';

import { CustomizeDistributorComponent } from '../components/distributors/distributor-details/customize-distributor/customize-distributor.component';
import { DistributorAddressComponent } from '../components/distributors/distributor-details/distributor-address/distributor-address.component';
import { DistributorDetailsComponent } from '../components/distributors/distributor-details/distributor-details/distributor-details.component';
import { DistributorExternalAuthenticationComponent } from '../components/distributors/distributor-details/distributor-external-authentication/distributor-external-authentication.component';
import { DistributorNotificationSettingsComponent } from '../components/distributors/distributor-details/distributor-notification-settings/distributor-notification-settings.component';
import { DistributorSettingsComponent } from '../components/distributors/distributor-details/distributor-settings/distributor-settings.component';
import { DistributorSslCertificatesComponent } from '../components/distributors/distributor-details/distributor-ssl-certificates/distributor-ssl-certificates.component';
import { EntitySection, AdminDetailSection } from '../models';
import { isEmpty } from '../../../shared/utils';

type EntitySectionRegistry = Record<
  string,
  {
    information: Type<EntitySection<unknown>>[];
    settings: Type<EntitySection<unknown>>[];
    statistics: Type<EntitySection<unknown>>[];
  }
>;

type EntityType = 'distributor' | 'vendor' | 'client';
type SectionType = 'information' | 'settings' | 'statistics';

@Injectable({
  providedIn: 'root',
})
export class AdminSectionRegistryService {
  private readonly sections: EntitySectionRegistry = {
    distributor: {
      information: [
        DistributorDetailsComponent,
        CustomizeDistributorComponent,
        DistributorAddressComponent,
        DistributorSslCertificatesComponent,
      ],
      settings: [
        DistributorSettingsComponent,
        DistributorNotificationSettingsComponent,
        DistributorExternalAuthenticationComponent,
      ],
      statistics: [],
    },
  };

  getSectionComponents(
    entityType: EntityType,
    sectionType: SectionType,
  ): Type<EntitySection<unknown>>[] {
    return !isEmpty(this.sections[entityType])
      ? this.sections[entityType][sectionType]
      : [];
  }

  createSections(
    entityType: EntityType,
    sectionType: SectionType,
    entity: unknown,
  ): AdminDetailSection[] {
    const components = this.getSectionComponents(entityType, sectionType);

    return components.map((component, index) => {
      // Determine title based on component name or metadata
      const title = this.getTitleForComponent(component);

      return {
        id: `${sectionType}-${index}`,
        title,
        component,
        componentInputs: { [entityType]: entity },
      };
    });
  }

  private getTitleForComponent(component: Type<unknown>): string {
    // Get component name and format it
    const name = component.name.replace(/Component$/, '');
    return name.replace(/([A-Z])/g, ' $1').trim();
  }

  registerEntityType(entityType: EntityType): void {
    if (isEmpty(this.sections[entityType])) {
      this.sections[entityType] = {
        information: [],
        settings: [],
        statistics: [],
      };
    }
  }
  registerComponent(
    entityType: EntityType,
    sectionType: SectionType,
    component: Type<EntitySection<unknown>>,
  ): void {
    this.registerEntityType(entityType);
    if (!this.sections[entityType][sectionType].includes(component)) {
      this.sections[entityType][sectionType].push(component);
    }
  }
}
